WITH influencers AS (SELECT id AS profile_id, is_brand OR is_verified AS label FROM profile WHERE visited_at > now() - INTERVAL '365 days'),
tested_profiles AS (
	FROM publication_collab pc
	JOIN publication p ON pc.publication_id = p.id
	WHERE p.profile_id IN (SELECT profile_id FROM influencers) AND is_private IS FALSE
),
followers AS (
	FROM profile_relationship pr JOIN tested_profiles tp ON pr.destination_profile_id = tp.profile_id
)
SELECT DISTINCT followers.* FROM followers;
